import { WorkflowContext, StepOutput } from 'mastra/workflows';

const piiPatterns = [
  /\b\d{3}-\d{2}-\d{4}\b/g, // SSN
  /\b4[0-9]{12}(?:[0-9]{3})?\b/g, // Visa
  /\b5[1-5][0-9]{14}\b/g, // Mastercard
  /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g // Email
];

export async function scanWorkflowOutput(ctx: WorkflowContext, output: StepOutput): Promise<boolean> {
  const outputString = JSON.stringify(output);
  return piiPatterns.some(pattern => pattern.test(outputString));
}

import { AgentToolCall, ToolResponse } from 'mastra/agents';

const secretPatterns = [
  /(?i)(api[-_]?key|secret|token|password|bearer)\s*[:=]\s*[\'\"]?[a-zA-Z0-9]{16,}/,
  /sk[-_][a-zA-Z0-9]{48}/, // OpenAI secret
  /ak[-_][a-zA-Z0-9]{20}/ // AWS access key
];

export function validateToolResponse(response: ToolResponse): { clean: boolean; matches: string[] } {
  const content = JSON.stringify(response.content);
  const matches = secretPatterns.filter(pattern => pattern.test(content));
  return { clean: matches.length === 0, matches: matches.map(m => m.source) };
}

import { MemoryContext, RetrievedMemory } from 'mastra/memory';

export function auditMemoryRetrieval(memories: RetrievedMemory[]): boolean {
  const sensitiveIndicators = ['ssn', 'credit card', 'api key', 'password', 'secret'];

  return memories.some(memory => {
    const lowerContent = memory.content.toLowerCase();
    return sensitiveIndicators.some(indicator => 
      lowerContent.includes(indicator) ||
      lowerContent.match(/\d{3}-\d{2}-\d{4}/) ||
      lowerContent.match(/\b4[0-9]{12}(?:[0-9]{3})?\b/)
    );
  });
}

