import { WorkflowMiddleware } from 'mastra/workflows';

import { redactPII } from './pii-redactor';

export const sanitizingMiddleware: WorkflowMiddleware = async (ctx, next) => {
  const originalOutput = ctx.stepOutput;

  // Redact PII from output before transition
  ctx.stepOutput = redactPII(originalOutput);

  // Log detection
  if (originalOutput !== ctx.stepOutput) {
    console.warn('PII detected and redacted in workflow output');
  }

  await next();
};

import { AgentTool } from 'mastra/agents';

import { sanitizeSecrets } from './secret-sanitizer';

export function createSafeTool<T extends AgentTool>(tool: T): T {
  return {
    ...tool,
    execute: async (input) => {
      const rawResult = await tool.execute(input);
      const sanitized = sanitizeSecrets(rawResult);

      // Log sanitization events
      if (rawResult !== sanitized) {
        console.warn('Secrets removed from tool response:', tool.name);
      }

      return sanitized;
    }
  } as T;
}

import { MemoryHook } from 'mastra/memory';

export const safeMemoryHook: MemoryHook = {
  async onRetrieve(memories, query) {
    return memories.filter(memory => {
      const hasSensitiveData = detectSensitiveData(memory.content);
      if (hasSensitiveData) {
        console.warn('Blocked sensitive memory retrieval:', memory.id);
      }
      return !hasSensitiveData;
    });
  }
};

function detectSensitiveData(content: string): boolean {
  const patterns = [/\d{3}-\d{2}-\d{4}/, /4[0-9]{12}/, /api[-_]?key/i];
  return patterns.some(p => p.test(content));
}

