import { MastraAgent, WorkflowConfig } from 'mastra';

const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY!
});

// Initialize Mastra agent with Vex middleware
export const agent = new MastraAgent({
  workflowConfig: {
    middleware: [
      vex.middleware.piiScanner({
        patterns: ['ssn', 'credit-card', 'api-key'],
        blockOnMatch: true
      }),
      vex.middleware.toolResponseValidator(),
      vex.middleware.memorySanitizer()
    ]
  }
});

// Vex auto-instruments all Mastra components
vex.monitorMastra(agent, {
  alertOn: ['pii-leak', 'secret-exposure'],
  autoRemediate: true
});
